import { use, useEffect, useState } from "react";
import "./conversion.css"
function Convertmain() {
let [currencies, changecurrencies] = useState()
let [chosencurr, changechosen] = useState("")
let [pairinfo, changepair] = useState()
useEffect(() => {
    async function loadcurrencyinfo() {

        let fetchcurr = await fetch("https://v6.exchangerate-api.com/v6/39655384f04dbe4478b4e6b2/codes")
        let jsoncurr = await fetchcurr.json()
        console.log(jsoncurr.supported_codes)
        let res = jsoncurr.supported_codes.map((item) => {
            return <option onClick={(e) => func1(e)} value={item[0]}>{item[1] + "/" + item[0]}</option>
        })
        changecurrencies(res)
    }
    loadcurrencyinfo()
}, [])
useEffect(() => {
    async function loadexchangeinfo() {
    let sessioncurr = await fetch("http://localhost:5000/currencysend", {
        method: "GET",
        headers: {"Content-Type":"application/json"},
        credentials: "include"
    })
    let sessioncurrget = await sessioncurr.json()
    console.log(sessioncurrget)
    if(chosencurr !== "") {
        let fetchexchange = await fetch(`https://v6.exchangerate-api.com/v6/39655384f04dbe4478b4e6b2/latest/${chosencurr}`)
        let jsonexchange = await fetchexchange.json()
        changepair(jsonexchange.conversion_rates)
    }
    }
    loadexchangeinfo()
    
}, [chosencurr])
async function func1(e) {
    changechosen(e.target.value)
    await fetch("http://localhost:5000/currencychoice", {
        method: "POST",
        headers: {"Content-Type":"application/json"},
        credentials: "include",
        body: JSON.stringify({currchosen: e.target.value})
    })
    console.log("fksdfjsdfjdf")

}
return<>
    <select id="options">
        {currencies}
    </select>
    <div>
        {pairinfo && Object.values(pairinfo).map((item) => {
            return<p>{item}</p>
        })}
    </div>
</>
}
export default Convertmain
